import socket
import json

# Game state and player list
game_state = 'In Progress'
player_list = ['Player1', 'Player2', 'Player3']

# Create a UDP socket
sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)

# Bind the socket to the port
server_address = ('localhost', 10000)
sock.bind(server_address)

while True:
    print('Waiting for a connection')
    data, address = sock.recvfrom(4096)

    print('Received request from', address)

    if data.decode() == 'status':
        # Create a dictionary with game state and player list
        server_status = {'game_state': game_state, 'player_list': player_list}
        # Convert dictionary to json
        server_status_json = json.dumps(server_status)
        # Send server status
        sent = sock.sendto(server_status_json.encode(), address)